const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
  rune: 60,
  moonstone: 60,
};

function calculateBasePremium(items: any[]): number {
  const groups: Record<string, any[]> = {};
  for (const item of items) {
    if (!groups[item.type]) groups[item.type] = [];
    groups[item.type].push(item);
  }

  let total = 0;
  for (const type of Object.keys(groups)) {
    const group = groups[type];
    if (group.length === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
      total += COMPONENT_BLOCK_PREMIUM[type];
    } else {
      total += group.length * BASE_PREMIUMS[type];
    }
  }
  return total;
}

function calculateItemSurcharges(items: any[]): number {
  let surcharges = 0;
  for (const item of items) {
    if (item.cursed) {
      surcharges += BASE_PREMIUMS[item.type] * 0.5;
    }
  }
  return surcharges;
}

function calculatePremium(items: any[]): number {
  const basePremium = calculateBasePremium(items);
  const itemSurcharges = calculateItemSurcharges(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
}

export function processScenario(scenario: any): unknown {
  const { items } = scenario.steps[0];
  const premium = calculatePremium(items);

  return { results: [{ premium }] };
